        function addMarker(id, address, image, description) {
            let customIcon = L.divIcon({
                className: 'custom-marker',
                html: `${id}.`, 
                iconSize: [20, 20],
                iconAnchor: [15, 30]
            });

            let url = 'https://nominatim.openstreetmap.org/search?format=json&q=' + encodeURIComponent(address);

            fetch(url)
                .then(response => response.json())
                .then(data => {
                    if (data && data.length > 0) {
                        let latlng = [data[0].lat, data[0].lon];
                        let customMarker = L.marker(latlng, { icon: customIcon }).addTo(map);
                        customMarker.on('click', function() {
                            let content = `<img src="${image}" alt="Object Image" style="max-width:100%;"><p>${description}</p>`;
                            document.getElementById('objectContent').innerHTML = content;
                        });
                    } else {
                        console.log('Address not found: ' + address);
                    }
                })
                .catch(err => console.log('Error:', err));
        }

        addMarker(1, "Laisvės al. 102, Kaunas", "test.png", "Aprašymas");
